PAIRWISE_JUDGE_PROMPT = """You are comparing two AI responses to the same task.

Task:
{task}

Response A:
{response_a}

Response B:
{response_b}

Which response better answers the task? Consider accuracy, completeness, and clarity.
Return JSON: {{"winner": "A" | "B" | "tie", "reason": "<one sentence>"}}
"""

def judge_pairwise(task: str, response_a: str, response_b: str) -> dict:
    import json, anthropic
    client = anthropic.Anthropic()
    prompt = PAIRWISE_JUDGE_PROMPT.format(
        task=task, response_a=response_a, response_b=response_b
    )
    msg = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=200,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(msg.content[0].text)

# To reduce order bias, run both orderings and aggregate
def judge_pairwise_debiased(task, a, b):
    r1 = judge_pairwise(task, a, b)  # A first
    r2 = judge_pairwise(task, b, a)  # B first (swap)
    # r2 winner is flipped (A in r2 is the original B)
    flipped = {"A": "B", "B": "A", "tie": "tie"}[r2["winner"]]
    if r1["winner"] == flipped:
        return r1["winner"]  # Both orderings agree
    return "tie"              # Disagree — call it a tie

REFERENCE_JUDGE_PROMPT = """You are evaluating whether an AI response covers the key information
in a reference answer.

Task:
{task}

Reference answer (ground truth):
{reference}

Model response to evaluate:
{response}

Does the model response cover all key points in the reference answer?
Identify any points that are missing or incorrect.
Return JSON:
{{
  "score": <0.0 to 1.0>,
  "missing_points": ["<point 1>", ...],
  "incorrect_points": ["<point 1>", ...]
}}
"""

def judge_reference(task: str, reference: str, response: str) -> dict:
    import json, anthropic
    client = anthropic.Anthropic()
    prompt = REFERENCE_JUDGE_PROMPT.format(
        task=task, reference=reference, response=response
    )
    msg = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=400,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(msg.content[0].text)
